mapper.select:
SELECT id as id, activityId as activityId, writeOffDate as writeOffDate, dealerId as dealerId, (select dealerName from dealer where id = dealerId) as dealerName, productId as productId, (select productName from product_config where id = productId) as productName, writeOffQuantity as writeOffQuantity, writeOffPrice as writeOffPrice, writeOffFee as writeOffFee FROM write_off_info
1=1
AND id = #{id}
AND activityId = #{activityId}
AND dealerId = #{dealerId}
ORDER BY id DESC
